class Solution {
    public int maxLengthBetweenEqualCharacters(String s) {
        int countA = 0;
        int countB = 0;
        int maxLength = -1;

        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == 'a') {
                countA++;
            } else {
                countB++;
            }

            if (countA > countB) {
                maxLength = Math.max(maxLength, countA);
                countA = 0;
            } else if (countB > countA) {
                maxLength = Math.max(maxLength, countB);
                countB = 0;
            }
        }

        if (countA > countB) {
            maxLength = Math.max(maxLength, countA);
        } else if (countB > countA) {
            maxLength = Math.max(maxLength, countB);
        }

        return maxLength;
    }
}
